import { useState, useEffect, useCallback, useRef } from "react";
import { Radio, AlertTriangle } from "lucide-react";
import { TelegramPost } from "./types";
import { CHANNELS } from "./lib/channels";
import { fetchAllChannels } from "./lib/telegram";
import PostCard from "./components/PostCard";
import FilterBar from "./components/FilterBar";
import StatusBar from "./components/StatusBar";

const REFRESH_INTERVAL = 60; // seconds

export default function App() {
  const [posts, setPosts] = useState<TelegramPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);
  const [activeRegion, setActiveRegion] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [lastRefresh, setLastRefresh] = useState<Date | null>(null);
  const [nextRefreshIn, setNextRefreshIn] = useState(REFRESH_INTERVAL);
  const [seenPostIds, setSeenPostIds] = useState<Set<string>>(new Set());
  const [newPostIds, setNewPostIds] = useState<Set<string>>(new Set());
  const [channelsLoaded, setChannelsLoaded] = useState(0);
  const isFirstLoad = useRef(true);

  const doFetch = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const allPosts = await fetchAllChannels(CHANNELS);

      const loadedChannels = new Set(allPosts.map(p => p.channelName));
      setChannelsLoaded(loadedChannels.size);

      if (isFirstLoad.current) {
        const ids = new Set(allPosts.map(p => p.id));
        setSeenPostIds(ids);
        setNewPostIds(new Set());
        isFirstLoad.current = false;
      } else {
        setSeenPostIds(prev => {
          const currentIds = new Set(allPosts.map(p => p.id));
          const newIds = new Set<string>();
          currentIds.forEach(id => {
            if (!prev.has(id)) newIds.add(id);
          });
          setNewPostIds(newIds);
          return new Set([...prev, ...currentIds]);
        });
      }

      setPosts(allPosts);
      setLastRefresh(new Date());
      setNextRefreshIn(REFRESH_INTERVAL);
    } catch (err) {
      setError("Failed to fetch channels. Retrying...");
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    doFetch();
  }, [doFetch]);

  useEffect(() => {
    const interval = setInterval(() => {
      doFetch();
    }, REFRESH_INTERVAL * 1000);
    return () => clearInterval(interval);
  }, [doFetch]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNextRefreshIn(prev => (prev <= 1 ? REFRESH_INTERVAL : prev - 1));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Compute counts
  const postCounts: Record<string, number> = {};
  const regionCounts: Record<string, number> = {};
  posts.forEach(p => {
    postCounts[p.channelName] = (postCounts[p.channelName] || 0) + 1;
    regionCounts[p.region] = (regionCounts[p.region] || 0) + 1;
  });

  // Reset filter if selected channel has 0 posts
  useEffect(() => {
    if (activeFilter && (postCounts[activeFilter] || 0) === 0) {
      setActiveFilter(null);
    }
  }, [postCounts, activeFilter]);

  // Reset region filter if no posts in region
  useEffect(() => {
    if (activeRegion && (regionCounts[activeRegion] || 0) === 0) {
      setActiveRegion(null);
    }
  }, [regionCounts, activeRegion]);

  // Filter & search
  const filteredPosts = posts.filter(p => {
    if (activeFilter && p.channelName !== activeFilter) return false;
    if (activeRegion && p.region !== activeRegion) return false;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      if (
        !p.text.toLowerCase().includes(q) &&
        !p.channelLabel.toLowerCase().includes(q) &&
        !p.region.toLowerCase().includes(q)
      ) {
        return false;
      }
    }
    return true;
  });

  return (
    <div className="w-full h-full flex flex-col bg-zinc-950 text-zinc-100 overflow-hidden">
      {/* Scanning header bar */}
      <div className="flex items-center gap-2 px-3 py-1.5 bg-zinc-900/60 border-b border-zinc-800/60">
        <Radio
          className="w-3.5 h-3.5 text-red-400"
          style={{
            animation: loading ? "pulse 1.5s ease-in-out infinite" : "none",
          }}
        />
        <span className="text-[11px] text-zinc-400 uppercase tracking-widest font-bold">
          TG Channel Monitor
        </span>
        <div className="flex-1" />
        <span className="text-[9px] text-zinc-600 uppercase tracking-wider">
          {channelsLoaded > 0 ? `${channelsLoaded}` : CHANNELS.length} / {CHANNELS.length} channels
        </span>
      </div>

      {/* Status bar with search */}
      <StatusBar
        totalPosts={filteredPosts.length}
        newCount={newPostIds.size}
        loading={loading}
        lastRefresh={lastRefresh}
        nextRefreshIn={nextRefreshIn}
        onRefresh={doFetch}
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        channelsLoaded={channelsLoaded}
        channelsTotal={CHANNELS.length}
      />

      {/* Filter bar with regions + channels */}
      <FilterBar
        channels={CHANNELS}
        activeFilter={activeFilter}
        activeRegion={activeRegion}
        onFilter={setActiveFilter}
        onRegionFilter={setActiveRegion}
        postCounts={postCounts}
        regionCounts={regionCounts}
      />

      {/* Error state */}
      {error && (
        <div className="flex items-center gap-2 px-3 py-2 bg-red-950/30 border-b border-red-900/30">
          <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
          <span className="text-[11px] text-red-300">{error}</span>
        </div>
      )}

      {/* Posts feed */}
      <div className="flex-1 overflow-y-auto">
        {loading && posts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full gap-3">
            <div className="relative">
              <div className="w-8 h-8 border-2 border-zinc-700 border-t-red-400 rounded-full animate-spin" />
            </div>
            <span className="text-[11px] text-zinc-500 tracking-wide">
              SCANNING CHANNELSÃ¢â‚¬Â¦
            </span>
            <div className="flex flex-wrap gap-1 items-center justify-center px-4 max-w-md">
              {CHANNELS.map(ch => (
                <span
                  key={ch.name}
                  className="text-[9px] px-1.5 py-0.5"
                  style={{ color: ch.color, backgroundColor: ch.bgColor }}
                >
                  {ch.label}
                </span>
              ))}
            </div>
          </div>
        ) : filteredPosts.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-32 gap-2">
            <span className="text-[11px] text-zinc-500">
              No posts match current filters
            </span>
            <button
              onClick={() => {
                setActiveFilter(null);
                setActiveRegion(null);
                setSearchQuery("");
              }}
              className="text-[10px] text-zinc-600 hover:text-zinc-400 transition-colors underline"
            >
              clear filters
            </button>
          </div>
        ) : (
          <div>
            {filteredPosts.map(post => (
              <PostCard
                key={post.id}
                post={post}
                isNew={newPostIds.has(post.id)}
              />
            ))}
          </div>
        )}
      </div>

      {/* Bottom status */}
      <div className="px-3 py-1 border-t border-zinc-800/60 flex items-center justify-between bg-zinc-900/40">
        <span className="text-[9px] text-zinc-600">
          {filteredPosts.length} messages
          {activeRegion ? ` Ã‚Â· ${activeRegion}` : ""}
          {activeFilter ? ` Ã‚Â· ${activeFilter}` : !activeRegion ? " Ã‚Â· all regions" : ""}
        </span>
        <span className="text-[9px] text-zinc-700">
          auto-refresh {REFRESH_INTERVAL}s
        </span>
      </div>

      {/* Pulse animation */}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.3; }
        }
        .scrollbar-none::-webkit-scrollbar { display: none; }
        .scrollbar-none { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
}

