import { useState } from "react";
import { formatDistanceToNow } from "date-fns";
import { Eye, Image, Video, FileText, Mic, ExternalLink, ChevronDown, ChevronUp } from "lucide-react";
import { TelegramPost } from "../types";
import { getChannelConfig } from "../lib/channels";

interface PostCardProps {
  post: TelegramPost;
  isNew: boolean;
}

export default function PostCard({ post, isNew }: PostCardProps) {
  const [expanded, setExpanded] = useState(false);
  const config = getChannelConfig(post.channelName);
  const truncateLength = 200;
  const needsTruncation = post.text.length > truncateLength;
  const displayText = expanded ? post.text : post.text.slice(0, truncateLength);

  let relativeTime = "just now";
  try {
    relativeTime = formatDistanceToNow(post.timestamp, { addSuffix: true });
  } catch {
    relativeTime = "unknown";
  }

  return (
    <div
      className="group border-b border-zinc-800/60 hover:bg-zinc-900/50 transition-colors relative"
      style={{ borderLeft: `2px solid ${config.color}` }}
    >
      {/* New indicator pulse */}
      {isNew && (
        <div className="absolute top-2 right-2 flex items-center gap-1">
          <span
            className="w-1.5 h-1.5 rounded-full animate-pulse"
            style={{ backgroundColor: "#ef4444", boxShadow: "0 0 6px #ef4444" }}
          />
          <span className="text-[9px] text-red-400 uppercase tracking-wider">new</span>
        </div>
      )}

      <div className="px-3 py-2">
        {/* Header row */}
        <div className="flex items-center gap-2 mb-1.5 flex-wrap">
          {/* Channel badge */}
          <span
            className="px-1.5 py-0.5 text-[10px] font-bold tracking-wide uppercase shrink-0"
            style={{
              color: config.color,
              backgroundColor: config.bgColor,
              border: `1px solid ${config.color}33`,
            }}
          >
            {config.label}
          </span>

          {/* Region tag */}
          <span className="text-[9px] text-zinc-600 bg-zinc-800/60 px-1 py-0.5 shrink-0">
            {post.region}
          </span>

          {/* Timestamp */}
          <span className="text-[10px] text-zinc-500 shrink-0">{relativeTime}</span>

          {/* View count */}
          {post.views && (
            <span className="flex items-center gap-0.5 text-[10px] text-zinc-600 shrink-0 ml-auto mr-6">
              <Eye className="w-3 h-3" />
              {post.views}
            </span>
          )}
        </div>

        {/* Media indicators */}
        {(post.hasPhoto || post.hasVideo || post.hasDocument || post.hasVoice) && (
          <div className="flex items-center gap-2 mb-1">
            {post.hasPhoto && (
              <span className="flex items-center gap-0.5 text-[9px] text-blue-400/80">
                <Image className="w-3 h-3" /> PHOTO
              </span>
            )}
            {post.hasVideo && (
              <span className="flex items-center gap-0.5 text-[9px] text-purple-400/80">
                <Video className="w-3 h-3" /> VIDEO
              </span>
            )}
            {post.hasDocument && (
              <span className="flex items-center gap-0.5 text-[9px] text-green-400/80">
                <FileText className="w-3 h-3" /> DOC
              </span>
            )}
            {post.hasVoice && (
              <span className="flex items-center gap-0.5 text-[9px] text-orange-400/80">
                <Mic className="w-3 h-3" /> VOICE
              </span>
            )}
          </div>
        )}

        {/* Message text */}
        <div className="text-[12px] text-zinc-300 leading-relaxed whitespace-pre-wrap break-words">
          {displayText}
          {needsTruncation && !expanded && (
            <span className="text-zinc-500">…</span>
          )}
        </div>

        {/* Expand/Collapse and Link */}
        <div className="flex items-center gap-3 mt-1.5">
          {needsTruncation && (
            <button
              onClick={() => setExpanded(!expanded)}
              className="flex items-center gap-0.5 text-[10px] text-zinc-500 hover:text-zinc-300 transition-colors"
            >
              {expanded ? (
                <>
                  <ChevronUp className="w-3 h-3" /> collapse
                </>
              ) : (
                <>
                  <ChevronDown className="w-3 h-3" /> expand
                </>
              )}
            </button>
          )}
          <a
            href={post.link}
            target="_blank"
            rel="noopener noreferrer"
            className="flex items-center gap-0.5 text-[10px] text-zinc-600 hover:text-zinc-300 transition-colors ml-auto"
          >
            <ExternalLink className="w-3 h-3" /> source
          </a>
        </div>
      </div>
    </div>
  );
}

