import { ChannelConfig } from "../types";
import { REGIONS } from "../lib/channels";

interface FilterBarProps {
  channels: ChannelConfig[];
  activeFilter: string | null;
  activeRegion: string | null;
  onFilter: (channelName: string | null) => void;
  onRegionFilter: (region: string | null) => void;
  postCounts: Record<string, number>;
  regionCounts: Record<string, number>;
}

export default function FilterBar({
  channels,
  activeFilter,
  activeRegion,
  onFilter,
  onRegionFilter,
  postCounts,
  regionCounts,
}: FilterBarProps) {
  const total = Object.values(postCounts).reduce((a, b) => a + b, 0);
  const activeChannels = channels.filter(ch => (postCounts[ch.name] || 0) > 0);
  const activeRegions = REGIONS.filter(r => (regionCounts[r] || 0) > 0);

  return (
    <div className="border-b border-zinc-800/60">
      {/* Region row */}
      <div className="flex items-center gap-1 px-3 py-1 overflow-x-auto scrollbar-none">
        <span className="text-[9px] text-zinc-600 uppercase tracking-wider mr-1 shrink-0">REGION</span>
        <button
          onClick={() => { onRegionFilter(null); onFilter(null); }}
          className="px-2 py-0.5 text-[10px] font-medium whitespace-nowrap transition-all shrink-0"
          style={{
            background: activeRegion === null && activeFilter === null ? "#e4e4e7" : "rgba(63,63,70,0.4)",
            color: activeRegion === null && activeFilter === null ? "#09090b" : "#71717a",
          }}
        >
          ALL ({total})
        </button>
        {activeRegions.map(region => {
          const count = regionCounts[region] || 0;
          const isActive = activeRegion === region;
          return (
            <button
              key={region}
              onClick={() => {
                onFilter(null);
                onRegionFilter(isActive ? null : region);
              }}
              className="px-2 py-0.5 text-[10px] font-medium whitespace-nowrap transition-all shrink-0"
              style={{
                background: isActive ? "rgba(161,161,170,0.2)" : "rgba(63,63,70,0.25)",
                color: isActive ? "#e4e4e7" : "#71717a",
                border: `1px solid ${isActive ? "rgba(161,161,170,0.3)" : "transparent"}`,
              }}
            >
              {region} ({count})
            </button>
          );
        })}
      </div>

      {/* Channel row */}
      <div className="flex items-center gap-1 px-3 py-1 overflow-x-auto scrollbar-none">
        <span className="text-[9px] text-zinc-600 uppercase tracking-wider mr-1 shrink-0">CH</span>
        {activeChannels
          .filter(ch => !activeRegion || ch.region === activeRegion)
          .map(ch => {
            const count = postCounts[ch.name] || 0;
            const isActive = activeFilter === ch.name;
            return (
              <button
                key={ch.name}
                onClick={() => onFilter(isActive ? null : ch.name)}
                className="px-2 py-0.5 text-[10px] font-medium whitespace-nowrap transition-all shrink-0"
                style={{
                  background: isActive ? ch.bgColor : "rgba(63,63,70,0.25)",
                  color: isActive ? ch.color : "#71717a",
                  border: `1px solid ${isActive ? ch.color + "44" : "transparent"}`,
                }}
              >
                {ch.label} ({count})
              </button>
            );
          })}
      </div>
    </div>
  );
}

